class Logger {
    context;
    level;
    constructor(context, level = 'info') {
        this.context = context;
        this.level = level;
    }
    shouldLog(level) {
        const levels = ['debug', 'info', 'warn', 'error'];
        return levels.indexOf(level) >= levels.indexOf(this.level);
    }
    format(entry) {
        const ctx = entry.context ? ` ${JSON.stringify(entry.context)}` : '';
        const dur = entry.duration ? ` [${entry.duration}ms]` : '';
        return `[${entry.timestamp}] [${entry.level.toUpperCase()}] [${this.context}] ${entry.message}${ctx}${dur}`;
    }
    debug(message, context) {
        if (!this.shouldLog('debug'))
            return;
        const entry = { timestamp: new Date().toISOString(), level: 'debug', message, context };
        console.debug(this.format(entry));
    }
    info(message, context) {
        if (!this.shouldLog('info'))
            return;
        const entry = { timestamp: new Date().toISOString(), level: 'info', message, context };
        console.info(this.format(entry));
    }
    warn(message, context) {
        if (!this.shouldLog('warn'))
            return;
        const entry = { timestamp: new Date().toISOString(), level: 'warn', message, context };
        console.warn(this.format(entry));
    }
    error(message, error, context) {
        if (!this.shouldLog('error'))
            return;
        const entry = {
            timestamp: new Date().toISOString(),
            level: 'error',
            message,
            context: { ...context, error: error?.message, stack: error?.stack },
        };
        console.error(this.format(entry));
    }
    time(label) {
        const start = Date.now();
        return () => {
            const duration = Date.now() - start;
            this.debug(`${label} completed`, { duration });
            return duration;
        };
    }
}
export const createLogger = (context, level) => new Logger(context, level);
export const log = createLogger('cvr', process.env.LOG_LEVEL || 'info');
