export function isError(e) {
    return e instanceof Error;
}
export function getErrorMessage(e) {
    if (isError(e))
        return e.message;
    if (typeof e === "string")
        return e;
    return "Unknown error";
}
export function isErrorWithMessage(e) {
    return (typeof e === "object" &&
        e !== null &&
        "message" in e &&
        typeof e.message === "string");
}
