let browserTools = null;
export async function getBrowserTools() {
    if (!browserTools) {
        try {
            browserTools = (await import("../browserTools.js"));
        }
        catch {
            return null;
        }
    }
    return browserTools;
}
export async function executeBrowserNavigate(params, sessionId) {
    const bt = await getBrowserTools();
    if (!bt)
        return { success: false, output: "", error: "playwright-core not installed" };
    const navResult = await bt.browserNavigate(sessionId, String(params.url), Boolean(params.headless ?? true));
    return {
        success: navResult.success,
        output: navResult.output ?? "",
        ...(navResult.error ? { error: navResult.error } : {}),
    };
}
