import * as path from "path";
import * as fs from "fs";
let _dbPath = path.resolve(process.cwd(), ".opencode-infinite", "rag.db");
let _db = null;
let _useFallback = false;
let _chunks = [];
let _jsonPath = "";
let _nextId = 1;
function loadJson() {
    try {
        if (fs.existsSync(_jsonPath)) {
            const raw = fs.readFileSync(_jsonPath, "utf-8");
            const data = JSON.parse(raw);
            _chunks = data.chunks || [];
            _nextId = data.nextId || 1;
        }
    }
    catch {
        /* ignore */
    }
}
function saveJson() {
    try {
        fs.mkdirSync(path.dirname(_jsonPath), { recursive: true });
        const data = { chunks: _chunks, nextId: _nextId };
        fs.writeFileSync(_jsonPath, JSON.stringify(data, null, 2));
    }
    catch {
        /* ignore */
    }
}
function fallbackGetDb() {
    if (!_jsonPath) {
        _jsonPath = _dbPath.replace(/\.db$/, "") + "-fallback.json";
        loadJson();
    }
    return {
        prepare: (sql) => {
            const trimmed = sql.trim().toLowerCase();
            if (trimmed.startsWith("insert into chunks")) {
                const stmt = {
                    run: (source, content, embedding) => {
                        _chunks.push({
                            id: _nextId++,
                            source: String(source),
                            content: String(content),
                            embedding: String(embedding),
                        });
                        saveJson();
                        return { lastInsertRowid: _nextId - 1, changes: 1 };
                    },
                };
                return stmt;
            }
            if (trimmed.startsWith("select") && trimmed.includes("from chunks")) {
                const stmt = {
                    all: () => [..._chunks],
                    get: () => undefined,
                };
                return stmt;
            }
            if (trimmed.startsWith("delete from chunks where source =")) {
                const stmt = {
                    run: (source) => {
                        _chunks = _chunks.filter((c) => c.source !== String(source));
                        saveJson();
                        return { lastInsertRowid: 0, changes: 1 };
                    },
                };
                return stmt;
            }
            const stmt = {
                run: () => ({ lastInsertRowid: 0, changes: 0 }),
                get: () => undefined,
                all: () => [],
            };
            return stmt;
        },
        exec: () => { },
        pragma: () => { },
    };
}
export function setRagDbPath(dir) {
    _dbPath = path.join(dir, "rag.db");
    _db = null;
    if (_useFallback) {
        _jsonPath = path.join(dir, "rag-fallback.json");
        loadJson();
    }
}
function getDb() {
    if (!_db) {
        try {
            const DatabaseClass = require("better-sqlite3");
            const db = new DatabaseClass(_dbPath);
            db.pragma("journal_mode = WAL");
            initSchema(db);
            _db = db;
        }
        catch {
            _useFallback = true;
            _db = fallbackGetDb();
        }
    }
    return _db;
}
function initSchema(db) {
    if (_useFallback)
        return;
    db.exec(`
    CREATE TABLE IF NOT EXISTS chunks (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      source TEXT NOT NULL,
      content TEXT NOT NULL,
      embedding TEXT NOT NULL
    );
    CREATE INDEX IF NOT EXISTS idx_chunks_source ON chunks(source);
  `);
}
function chunkText(text, maxChars = 500) {
    const chunks = [];
    const sentences = text.match(/[^.!?]+[.!?]+/g) || [text];
    let current = "";
    for (const sentence of sentences) {
        if ((current + sentence).length > maxChars && current.length > 0) {
            chunks.push(current.trim());
            current = sentence;
        }
        else {
            current += sentence;
        }
    }
    if (current.trim())
        chunks.push(current.trim());
    return chunks.length ? chunks : [text];
}
function cosineSimilarity(a, b) {
    let dot = 0;
    let normA = 0;
    let normB = 0;
    for (let i = 0; i < a.length; i++) {
        const av = a[i];
        const bv = b[i];
        dot += av * bv;
        normA += av * av;
        normB += bv * bv;
    }
    if (normA === 0 || normB === 0)
        return 0;
    return dot / (Math.sqrt(normA) * Math.sqrt(normB));
}
export async function ingestDocument(source, content, embedFn) {
    const db = getDb();
    const chunks = chunkText(content);
    const embeddings = await embedFn(chunks);
    const insert = db.prepare("INSERT INTO chunks (source, content, embedding) VALUES (?, ?, ?)");
    for (let i = 0; i < chunks.length; i++) {
        insert.run(source, chunks[i], JSON.stringify(embeddings[i]));
    }
    if (_useFallback)
        saveJson();
}
export async function searchRAG(query, embedFn, topK = 3) {
    const db = getDb();
    const [queryEmbedding] = await embedFn([query]);
    if (!queryEmbedding)
        return [];
    const rows = db.prepare("SELECT source, content, embedding FROM chunks").all();
    const scored = rows
        .map((r) => ({
        source: r.source,
        content: r.content,
        score: cosineSimilarity(queryEmbedding, JSON.parse(r.embedding)),
    }))
        .filter((r) => r.score > 0.5)
        .sort((a, b) => b.score - a.score)
        .slice(0, topK);
    return scored;
}
export function listSources() {
    const db = getDb();
    const rows = db.prepare("SELECT DISTINCT source FROM chunks").all();
    return rows.map((r) => r.source);
}
export function clearSource(source) {
    const db = getDb();
    db.prepare("DELETE FROM chunks WHERE source = ?").run(source);
    if (_useFallback)
        saveJson();
}
